1	import { PlaywrightExecutor } from "./playwright-executor";
2	import type {
3	  Scenario,
4	  ScenarioResult,
5	  Step,
6	  StepResult,
7	  TestCase,
8	  TestCaseResult,
9	  TiberoConfig,
10	} from "./types.js";
11	
12	interface RunScenarioOptions {
13	  onTestCaseStart?: (
14	    testCase: TestCase,
15	    testCaseIndex: number,
16	    totalTestCases: number
17	  ) => void | Promise<void>;
18	  onStepStart?: (
19	    testCase: TestCase,
20	    testCaseIndex: number,
21	    step: Step,
22	    stepIndex: number
23	  ) => void | Promise<void>;
24	  onStepComplete?: (
25	    testCase: TestCase,
26	    testCaseIndex: number,
27	    result: StepResult,
28	    stepIndex: number,
29	    executedStepCount: number
30	  ) => void | Promise<void>;
31	  onTestCaseComplete?: (
32	    testCase: TestCase,
33	    testCaseIndex: number,
34	    result: TestCaseResult
35	  ) => void | Promise<void>;
36	}
37	
38	async function runTestCase(
39	  testCase: TestCase,
40	  executor: PlaywrightExecutor,
41	  scenarioDbConfig?: TiberoConfig,
42	  options: Omit<RunScenarioOptions, "onTestCaseStart" | "onTestCaseComplete"> = {},
43	  testCaseIndex = 0
44	): Promise<TestCaseResult> {
45	  const dbConfig = testCase.dbConfig ?? scenarioDbConfig;
46	  const startedAt = Date.now();
47	
48	  const stepResults = await executor.executeSteps(
49	    testCase.steps,
50	    dbConfig,
51	    {
52	      onStepStart: (step, stepIndex) =>
53	        options.onStepStart?.(testCase, testCaseIndex, step, stepIndex),
54	      onStepComplete: (result, stepIndex, executedStepCount) =>
55	        options.onStepComplete?.(testCase, testCaseIndex, result, stepIndex, executedStepCount),
56	    },
57	    testCase.baseUrl || undefined
58	  );
59	  const hasError = stepResults.some((result) => result.status === "error");
60	
61	  return {
62	    testCaseId: testCase.id,
63	    testCaseName: testCase.name,
64	    status: hasError ? "error" : "passed",
65	    executionTime: Date.now() - startedAt,
66	    stepResults,
67	  };
68	}
69	
70	export async function runScenario(
71	  scenario: Scenario,
72	  options: RunScenarioOptions = {}
73	): Promise<ScenarioResult> {
74	  const testCaseResults: TestCaseResult[] = [];
75	  const executor = new PlaywrightExecutor();
76	
77	  try {
78	    await executor.initialize();
79	
80	    for (const [testCaseIndex, testCase] of scenario.testCases.entries()) {
81	      await options.onTestCaseStart?.(testCase, testCaseIndex, scenario.testCases.length);
82	      const result = await runTestCase(testCase, executor, scenario.dbConfig, options, testCaseIndex);
83	      testCaseResults.push(result);
84	      await options.onTestCaseComplete?.(testCase, testCaseIndex, result);
85	    }
86	  } finally {
87	    await executor.close();
88	  }
89	
90	  return {
91	    scenarioId: scenario.id,
92	    scenarioName: scenario.name,
93	    executedAt: new Date().toISOString(),
94	    testCaseResults,
95	  };
96	}
